import Database from "better-sqlite3";
import { fileURLToPath } from "node:url";

/**
 * Server-only database access module.
 *
 * IMPORTANT: This module must only ever be imported from within
 * `routeLoader$`/`routeAction$`/`onGet` (etc.) closures so the Qwik
 * optimizer keeps `better-sqlite3` out of the client bundle.
 */

export interface Transaction {
  id: number;
  date: string;
  category: string;
  description: string;
  amount: number;
}

export interface TransactionFilters {
  from?: string;
  to?: string;
  category?: string;
}

const dbPath = fileURLToPath(
  new URL("../../data/reports.db", import.meta.url),
);

let db: InstanceType<typeof Database> | undefined;

function getDb() {
  if (!db) {
    db = new Database(dbPath, { readonly: true, fileMustExist: true });
  }
  return db;
}

export function getTransactions(
  filters: TransactionFilters = {},
): Transaction[] {
  const conditions: string[] = [];
  const params: Record<string, string> = {};

  if (filters.from) {
    conditions.push("date >= @from");
    params.from = filters.from;
  }
  if (filters.to) {
    conditions.push("date <= @to");
    params.to = filters.to;
  }
  if (filters.category) {
    conditions.push("category = @category");
    params.category = filters.category;
  }

  const where = conditions.length ? `WHERE ${conditions.join(" AND ")}` : "";
  const sql = `SELECT id, date, category, description, amount FROM transactions ${where} ORDER BY id ASC`;

  return getDb().prepare(sql).all(params) as Transaction[];
}

import type { Transaction } from "./db";

const CSV_HEADER = "id,date,category,description,amount";

/**
 * Escapes a single CSV field per RFC 4180: if the value contains a comma,
 * a double quote, or a newline (CR or LF), it is wrapped in double quotes
 * and any internal double quotes are doubled.
 */
export function csvField(value: string | number): string {
  const str = String(value);
  if (/[",\r\n]/.test(str)) {
    return `"${str.replace(/"/g, '""')}"`;
  }
  return str;
}

/**
 * Converts a list of transactions into an RFC 4180 compliant CSV string,
 * using CRLF as the record separator.
 */
export function transactionsToCsv(rows: Transaction[]): string {
  const lines = rows.map((row) =>
    [row.id, row.date, row.category, row.description, row.amount]
      .map(csvField)
      .join(","),
  );

  return [CSV_HEADER, ...lines].map((line) => line).join("\r\n") + "\r\n";
}

import { component$ } from "@builder.io/qwik";
import { routeLoader$, type DocumentHead } from "@builder.io/qwik-city";
import { getTransactions } from "~/lib/db";

export const useTransactions = routeLoader$(({ query }) => {
  const from = query.get("from") ?? undefined;
  const to = query.get("to") ?? undefined;
  const category = query.get("category") ?? undefined;

  const transactions = getTransactions({ from, to, category });

  return { from, to, category, transactions };
});

function buildExportHref(filters: {
  from?: string;
  to?: string;
  category?: string;
}): string {
  const params = new URLSearchParams();
  if (filters.from) params.set("from", filters.from);
  if (filters.to) params.set("to", filters.to);
  if (filters.category) params.set("category", filters.category);
  const qs = params.toString();
  return `/reports/export${qs ? `?${qs}` : ""}`;
}

export default component$(() => {
  const data = useTransactions();
  const { from, to, category, transactions } = data.value;

  return (
    <>
      <h1>Transaction Report</h1>

      <form>
        <label>
          From
          <input type="date" name="from" value={from ?? ""} />
        </label>
        <label>
          To
          <input type="date" name="to" value={to ?? ""} />
        </label>
        <label>
          Category
          <input type="text" name="category" value={category ?? ""} />
        </label>
        <button type="submit">Filter</button>
      </form>

      <p>
        <a href={buildExportHref({ from, to, category })}>Download CSV</a>
      </p>

      <table>
        <thead>
          <tr>
            <th>ID</th>
            <th>Date</th>
            <th>Category</th>
            <th>Description</th>
            <th>Amount</th>
          </tr>
        </thead>
        <tbody>
          {transactions.map((t) => (
            <tr key={t.id}>
              <td>{t.id}</td>
              <td>{t.date}</td>
              <td>{t.category}</td>
              <td>{t.description}</td>
              <td>{t.amount}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </>
  );
});

export const head: DocumentHead = {
  title: "Transaction Report",
  meta: [
    {
      name: "description",
      content: "Filterable expense transaction report",
    },
  ],
};

import type { RequestHandler } from "@builder.io/qwik-city";
import { getTransactions } from "~/lib/db";
import { transactionsToCsv } from "~/lib/csv";

export const onGet: RequestHandler = async (requestEvent) => {
  const { query, send } = requestEvent;

  const from = query.get("from") ?? undefined;
  const to = query.get("to") ?? undefined;
  const category = query.get("category") ?? undefined;

  const transactions = getTransactions({ from, to, category });
  const csv = transactionsToCsv(transactions);

  requestEvent.headers.set("Content-Type", "text/csv; charset=utf-8");
  requestEvent.headers.set(
    "Content-Disposition",
    'attachment; filename="transactions.csv"',
  );

  send(200, csv);
};
